const ITERATIONS = 100_000;
const HASH_LENGTH = 32; // bytes
const SALT_LENGTH = 16; // bytes

/**
 * Hash a plain-text password with PBKDF2/SHA-256.
 * Returns a base64-encoded string: "<salt_hex>:<hash_hex>"
 */
export async function hashPassword(password: string): Promise<string> {
  const salt = crypto.getRandomValues(new Uint8Array(SALT_LENGTH));

  const keyMaterial = await crypto.subtle.importKey(
    "raw",
    new TextEncoder().encode(password),
    "PBKDF2",
    false,
    ["deriveBits"]
  );

  const hashBuffer = await crypto.subtle.deriveBits(
    {
      name: "PBKDF2",
      hash: "SHA-256",
      salt,
      iterations: ITERATIONS,
    },
    keyMaterial,
    HASH_LENGTH * 8
  );

  const saltHex = Array.from(salt)
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");
  const hashHex = Array.from(new Uint8Array(hashBuffer))
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");

  return `${saltHex}:${hashHex}`;
}

/**
 * Verify a plain-text password against a stored hash string.
 * The stored string has the format "<salt_hex>:<hash_hex>".
 */
export async function verifyPassword(
  password: string,
  stored: string
): Promise<boolean> {
  const [saltHex, storedHashHex] = stored.split(":");
  if (!saltHex || !storedHashHex) return false;

  const salt = new Uint8Array(
    saltHex.match(/.{2}/g)!.map((byte) => parseInt(byte, 16))
  );

  const keyMaterial = await crypto.subtle.importKey(
    "raw",
    new TextEncoder().encode(password),
    "PBKDF2",
    false,
    ["deriveBits"]
  );

  const hashBuffer = await crypto.subtle.deriveBits(
    {
      name: "PBKDF2",
      hash: "SHA-256",
      salt,
      iterations: ITERATIONS,
    },
    keyMaterial,
    HASH_LENGTH * 8
  );

  const hashHex = Array.from(new Uint8Array(hashBuffer))
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");

  return hashHex === storedHashHex;
}

import { drizzle } from "drizzle-orm/d1";
import { eq } from "drizzle-orm";
import { users } from "../db/schema";
import { hashPassword, verifyPassword } from "../lib/password";

function json(data: unknown, status = 200): Response {
  return new Response(JSON.stringify(data), {
    status,
    headers: { "Content-Type": "application/json" },
  });
}

export async function handleRegister(request: Request, env: Env): Promise<Response> {
  let body: { email?: string; password?: string; displayName?: string | null };
  try {
    body = await request.json();
  } catch {
    return json({ error: "Invalid JSON" }, 400);
  }

  const { email, password, displayName = null } = body;

  if (!email || !password) {
    return json({ error: "email and password are required" }, 400);
  }

  const db = drizzle(env.DB);

  // Check for existing user
  const existing = await db
    .select({ id: users.id })
    .from(users)
    .where(eq(users.email, email))
    .get();

  if (existing) {
    return json({ error: "Email already exists" }, 409);
  }

  const password_hash = await hashPassword(password);
  const created_at = Date.now();

  const inserted = await db
    .insert(users)
    .values({
      email,
      password_hash,
      created_at,
      display_name: displayName ?? null,
    })
    .returning({ id: users.id, email: users.email, display_name: users.display_name })
    .get();

  return json(
    {
      id: inserted.id,
      email: inserted.email,
      displayName: inserted.display_name ?? null,
    },
    201
  );
}

export async function handleLogin(request: Request, env: Env): Promise<Response> {
  let body: { email?: string; password?: string };
  try {
    body = await request.json();
  } catch {
    return json({ error: "Invalid JSON" }, 400);
  }

  const { email, password } = body;

  if (!email || !password) {
    return json({ error: "email and password are required" }, 400);
  }

  const db = drizzle(env.DB);

  const user = await db
    .select()
    .from(users)
    .where(eq(users.email, email))
    .get();

  if (!user) {
    return json({ error: "Invalid credentials" }, 401);
  }

  const valid = await verifyPassword(password, user.password_hash);
  if (!valid) {
    return json({ error: "Invalid credentials" }, 401);
  }

  return json({
    id: user.id,
    email: user.email,
    displayName: user.display_name ?? null,
  });
}

export async function handleListUsers(_request: Request, env: Env): Promise<Response> {
  const db = drizzle(env.DB);

  const allUsers = await db
    .select({
      id: users.id,
      email: users.email,
      display_name: users.display_name,
      created_at: users.created_at,
    })
    .from(users)
    .all();

  return json(
    allUsers.map((u) => ({
      id: u.id,
      email: u.email,
      displayName: u.display_name ?? null,
      createdAt: u.created_at,
    }))
  );
}

import { defineApp } from "rwsdk/worker";
import { route } from "rwsdk/router";
import { handleRegister, handleLogin, handleListUsers } from "./api/auth";

export default defineApp([
  route("/api/auth/register", {
    post: ({ request, env }) => handleRegister(request, env),
  }),
  route("/api/auth/login", {
    post: ({ request, env }) => handleLogin(request, env),
  }),
  route("/api/users", {
    get: ({ request, env }) => handleListUsers(request, env),
  }),
]);

